#include <vector>
#include <string>
#include <algorithm>
#include <regex>

using namespace std;

vector<string> solve(vector<string> code, vector<string> businessLine, vector<bool> isActive) {
    vector<string> validCoupons;
    vector<pair<int, string>> categorizedCoupons;

    // Define the order of business lines
    vector<string> businessOrder = {"electronics", "grocery", "pharmacy", "restaurant"};

    // Regex to check valid code (alphanumeric and underscore only)
    regex codeRegex("^[a-zA-Z0-9_]+$");

    for (size_t i = 0; i < code.size(); ++i) {
        // Check all conditions for validity
        bool isValid = true;

        // Check code is not empty and matches regex
        if (code[i].empty() || !regex_match(code[i], codeRegex)) {
            isValid = false;
        }

        // Check businessLine is valid
        if (find(businessOrder.begin(), businessOrder.end(), businessLine[i]) == businessOrder.end()) {
            isValid = false;
        }

        // Check isActive is true
        if (!isActive[i]) {
            isValid = false;
        }

        if (isValid) {
            // Find the priority of the businessLine
            auto it = find(businessOrder.begin(), businessOrder.end(), businessLine[i]);
            int priority = distance(businessOrder.begin(), it);
            categorizedCoupons.emplace_back(priority, code[i]);
        }
    }

    // Sort by businessLine priority, then by code lexicographical order
    sort(categorizedCoupons.begin(), categorizedCoupons.end(), 
        [](const pair<int, string>& a, const pair<int, string>& b) {
            if (a.first != b.first) {
                return a.first < b.first;
            } else {
                return a.second < b.second;
            }
        });

    // Extract the sorted codes
    for (const auto& entry : categorizedCoupons) {
        validCoupons.push_back(entry.second);
    }

    return validCoupons;
}

