use regex::Regex;

fn solve(code: Vec<String>, business_line: Vec<String>, is_active: Vec<bool>) -> Vec<String> {
    let business_order = vec!["electronics", "grocery", "pharmacy", "restaurant"];
    let code_regex = Regex::new(r"^[a-zA-Z0-9_]+$").unwrap();
    let mut categorized_coupons = Vec::new();

    for i in 0..code.len() {
        if !is_active[i] {
            continue;
        }

        if code[i].is_empty() || !code_regex.is_match(&code[i]) {
            continue;
        }

        if let Some(priority) = business_order.iter().position(|&bl| bl == business_line[i]) {
            categorized_coupons.push((priority, code[i].clone()));
        }
    }

    categorized_coupons.sort_by(|a, b| {
        if a.0 != b.0 {
            a.0.cmp(&b.0)
        } else {
            a.1.cmp(&b.1)
        }
    });

    categorized_coupons.into_iter().map(|(_, code)| code).collect()
}
